                  className="flex-1 py-3 text-center text-[10px] font-black uppercase tracking-widest rounded-xl bg-stone-900 text-white hover:bg-stone-800 transition-colors shadow-md cursor-pointer"
                >
                  Save Bookmark
                </button>
              </div>
            </form>

          </div>
        </div>
      )}

    </div>
  );
};

